### 五、Bevy ECS 设计

> 以下组件与系统均为设计稿，引用的类型（`PlayerCultivation`、`TrueQi`、`PlayerAction`、`NarrationEvent`、`SpawnMonsterEvent` 等）尚未在 `server/` 中实现。

#### 5.1 组件结构

```rust
// server/src/world/regions/blood_valley.rs

use bevy::prelude::*;

/// 区域配置组件——标记血谷整体范围
#[derive(Component, Clone, Debug)]
pub struct BloodValleyRegion {
    pub center: Vec2,           // (3000.0, -2500.0)
    pub bounds: Vec2,           // (800.0, 1500.0) 东西×南北
    pub base_spirit: f32,       // 0.3
    pub domain_collapse_timer: Option<f32>, // 域崩倒计时（秒）
    pub player_count: u32,
    pub player_count_timer: f32, // 连续满员计时
}

impl Default for BloodValleyRegion {
    fn default() -> Self {
        Self {
            center: Vec2::new(3000.0, -2500.0),
            bounds: Vec2::new(800.0, 1500.0),
            base_spirit: 0.3,
            domain_collapse_timer: None,
            player_count: 0,
            player_count_timer: 0.0,
        }
    }
}

/// 子区域灵气组件——每个子区域独立追踪
#[derive(Component, Clone, Debug)]
pub struct ZoneSpirit {
    pub zone_type: BloodValleyZone,
    pub current_spirit: f32,
    pub permanent_decay: f32,    // 永久衰减累计值
    pub last_player_activity: f32, // 上次有玩家活动的时间戳
    pub ore_remaining: u32,      // 矿脉剩余方块数
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum BloodValleyZone {
    CleftBeach,      // 裂口滩
    RedMarrowGully,  // 赤髓沟
    StarfallPit,     // 坠星坑
    NarrowThroat,    // 狭喉
    BoneHeapTerrace, // 骨堆台
    BrokenSpineAbyss,// 断脊渊
}

impl ZoneSpirit {
    pub fn new(zone: BloodValleyZone) -> Self {
        let base = match zone {
            BloodValleyZone::CleftBeach => 0.25,
            BloodValleyZone::RedMarrowGully => 0.30,
            BloodValleyZone::StarfallPit => 0.20,
            BloodValleyZone::NarrowThroat => 0.35,
            BloodValleyZone::BoneHeapTerrace => 0.28,
            BloodValleyZone::BrokenSpineAbyss => 0.10,
        };
        Self {
            zone_type: zone,
            current_spirit: base,
            permanent_decay: 0.0,
            last_player_activity: 0.0,
            ore_remaining: Self::initial_ore(zone),
        }
    }

    fn initial_ore(zone: BloodValleyZone) -> u32 {
        match zone {
            BloodValleyZone::CleftBeach => 200,
            BloodValleyZone::RedMarrowGully => 350,
            BloodValleyZone::StarfallPit => 500,
            BloodValleyZone::BoneHeapTerrace => 150,
            BloodValleyZone::BrokenSpineAbyss => 800,
            _ => 100,
        }
    }
}

/// 负灵域标记组件——用于坠星坑坑底和断脊渊裂隙
#[derive(Component)]
pub struct NegativeSpiritZone {
    pub spirit_value: f32,      // 负数，如 -0.8
    pub drain_rate_multiplier: f32, // 境界越高吸速倍率越高
}

/// 血谷专属生物生成表
#[derive(Component, Clone)]
pub struct BloodValleySpawnTable {
    pub zone: BloodValleyZone,
    pub spirit_threshold: f32,   // 灵气低于此值触发生态迁移
    pub max_spawns: u32,
    pub current_spawns: u32,
}
```

#### 5.2 系统函数签名

```rust
// server/src/world/systems/spirit_decay.rs

use bevy::prelude::*;
use crate::world::regions::blood_valley::{BloodValleyRegion, ZoneSpirit, BloodValleyZone};

/// 血谷灵气衰减系统
/// 每 30 秒执行一次，检测玩家打坐、突破、采矿行为并扣减灵气
pub fn blood_valley_spirit_decay_system(
    time: Res<Time>,
    mut region_query: Query<&mut BloodValleyRegion>,
    mut zone_query: Query<(Entity, &mut ZoneSpirit, &Transform)>,
    player_query: Query<(&Transform, &PlayerCultivation, &PlayerAction), With<Player>>,
    mut narration_events: EventWriter<NarrationEvent>,
) {
    // 实现要点：
    // 1. 遍历玩家，判断所在子区域（通过 Transform 坐标）
    // 2. 若玩家状态为 Meditating，对应 zone.current_spirit -= 0.01
    // 3. 若玩家触发 Breakthrough 事件，对应 zone.current_spirit -= 0.03（永久）
    // 4. 更新 region.player_count，检测是否触发域崩倒计时
    // 5. 无玩家活动的 zone，每 10 分钟恢复 current_spirit = min(base, current_spirit + 0.005)
}
```

