    mut player_query: Query<(&Transform, &mut PlayerCultivation, &mut TrueQi)>,
    negative_zone_query: Query<(&NegativeSpiritZone, &Transform)>,
    time: Res<Time>,
) {
    // 实现要点：
    // 1. 检测玩家坐标是否在 NegativeSpiritZone 范围内
    // 2. drain_rate = base_rate * (1.0 + player.max_qi / 100.0) * |spirit_value|
    // 3. 示例：通灵境(max=300)在 -0.8 区域 = 0.8 * 4.0 = 3.2 真元/秒
    // 4. 真元归零后继续停留，扣除境界经验值（可能导致降阶）
}
